            let [secondCnt, secondChar] = pq.dequeue();
            result += secondChar;
            secondCnt--;
            if (secondCnt !== 0) pq.enqueue([secondCnt, secondChar]);
            pq.enqueue([firstCnt, firstChar]);
        } else {
            break;
        }
    }
    return result;
};
